namespace BgCommon.Text.Json.Converters;/// <summary>/// long格式Json转换器./// </summary>public class LongJsonConverter : JsonConverter<long>{    /// <inheritdoc/>    public override long Read(ref Utf8JsonReader reader, Type typeToConvert, JsonSerializerOptions options)    {        if (reader.TokenType == JsonTokenType.String)        {            return BgConvert.ToLong(reader.GetString());        }        return reader.TryGetInt64(out var value) ? value : 0;    }    /// <inheritdoc/>    public override void Write(Utf8JsonWriter writer, long value, JsonSerializerOptions options)    {        writer.WriteStringValue(value.SafeString());    }}